```class Solution {
public:
    bool possibleBipartition(int n, vector<vector<int>>& dislikes) {
        vector<int> group(n + 1, 0);
        for (auto& dislike : dislikes) {
            int a = dislike[0], b = dislike[1];
            if (group[a] == group[b]) return false;
            group[a] = -group[b];
        }
        return true;
    }
};```
